import React from 'react'
import PropTypes from 'prop-types' // impt(단축키)

const Program_icon = (props) => {
    var result = [];
    var location = "program_icon/";
    for (let i = 0; i < props.icons.length; i++) {
        result.push(
            <div className='program'>
                <img src={location + props.icons[i]} alt='이미지 없음'></img>
            </div>
        )
    }
    return (
        result
    )
}

Program_icon.prototype = {
    // isRequired: 이 요소는 필수로 있어야 한다.
    // PropTypes.arrayOf(PropTypes.string) 이렇게만 쓰면 필수요소가 아니다.
    // 배열 형식 정의
    icons: PropTypes.arrayOf(PropTypes.string).isRequired,
}

export default Program_icon