import React from 'react'

const Slider = () => {
  function SliderEvent() {
    /*
      div사이즈 동적으로 구하기
    */
    const outer = document.querySelector('.slide');
    const innerList = document.querySelector('.slideList');
    const inners = document.querySelectorAll('.slidePage');
    let currentIndex = 0; // 현재 슬라이드 화면 인덱스

    inners.forEach((inner) => {
      inner.style.width = `${outer.clientWidth}px`; // inner의 width를 모두 outer의 width로 만들기
    })

    innerList.style.width = `${outer.clientWidth * inners.length}px`; // innerList의 width를 inner의 width * inner의 개수로 만들기

    /*
      버튼에 이벤트 등록하기
    */
    const buttonLeft = document.querySelector('.leftBTN');
    const buttonRight = document.querySelector('.rightBTN');

    buttonLeft.addEventListener('click', () => {
      currentIndex--;
      currentIndex = currentIndex < 0 ? 0 : currentIndex; // index값이 0보다 작아질 경우 0으로 변경
      innerList.style.marginLeft = `-${outer.clientWidth * currentIndex}px`; // index만큼 margin을 주어 옆으로 밀기
    });

    buttonRight.addEventListener('click', () => {
      currentIndex++;
      currentIndex = currentIndex >= inners.length ? inners.length - 1 : currentIndex; // index값이 inner의 총 개수보다 많아질 경우 마지막 인덱스값으로 변경
      innerList.style.marginLeft = `-${outer.clientWidth * currentIndex}px`; // index만큼 margin을 주어 옆으로 밀기
    });
  }
  return (
    <div style={{position: "relative"}} onLoad={SliderEvent}>
      <div className='leftBTN'></div>
      <div class="slide">
        <div class="slideList">
          <div class="slidePage">
            <img src='project01_img/Sollind1.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind2.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind3.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind4.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind5.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind6.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind7.PNG' alt='이미지 없음'></img>
          </div>
          <div class="slidePage">
            <img src='project01_img/Sollind8.PNG' alt='이미지 없음'></img>
          </div>
        </div>
      </div>
      <div className='rightBTN'></div>
    </div>
  )
}

export default Slider